import React, { useState } from 'react';
import { UserRole } from '../types';
import { login } from '../services/authService';
import { Button } from './Button';
import { Input } from './Input';
import { User, Lock, GraduationCap, BookOpen, CheckCircle2 } from 'lucide-react';

interface LoginFormProps {
  onLoginSuccess: (user: import('../types').User) => void;
}

export const LoginForm: React.FC<LoginFormProps> = ({ onLoginSuccess }) => {
  const [activeRole, setActiveRole] = useState<UserRole>(UserRole.STUDENT);
  const [id, setId] = useState(''); // This acts as Roll Number for students, and ID for teachers
  const [name, setName] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [imageError, setImageError] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setIsLoading(true);

    try {
      const user = await login(id, name, activeRole);
      onLoginSuccess(user);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Login failed');
    } finally {
      setIsLoading(false);
    }
  };

  const handleRoleChange = (role: UserRole) => {
    setActiveRole(role);
    setError(null);
    // Optional: Clear inputs on role switch if desired, but keeping them might be friendlier
  };

  return (
    <div className="min-h-screen w-full flex flex-col items-center justify-center bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">

      <div className="w-full max-w-md space-y-8">
        {/* Branding Section */}
        <div className="flex flex-col items-center text-center animate-in fade-in slide-in-from-top-4 duration-700">

          {/* Logo Container */}
          <div className="w-48 h-48 mb-6 relative flex items-center justify-center">
            <img 
              src="images/Khlogo.webp"
              alt="K.H. Matriculation School Logo" 
              className={`w-full h-full object-contain drop-shadow-xl hover:scale-105 transition-transform duration-300 ${imageError ? 'hidden' : 'block'}`}
              onError={(e) => {
                setImageError(true);
              }}
            />

            {imageError && (
              // Fallback SVG
              <div className="w-full h-full drop-shadow-xl hover:scale-105 transition-transform duration-300 animate-in fade-in">
                 <svg viewBox="0 0 200 200" className="w-full h-full">
                    <circle cx="100" cy="100" r="95" fill="white" stroke="#006400" strokeWidth="3" />
                    <circle cx="100" cy="100" r="85" fill="none" stroke="#006400" strokeWidth="1" />
                    <path d="M 50,60 Q 100,20 150,60 V 120 Q 100,180 50,120 Z" fill="#FFFFE0" stroke="#006400" strokeWidth="2" />
                    <path d="M 70,90 Q 100,100 130,90 V 130 Q 100,140 70,130 Z" fill="none" stroke="#006400" strokeWidth="2" />
                    <line x1="100" y1="95" x2="100" y2="135" stroke="#006400" strokeWidth="2" />
                    <text x="100" y="80" textAnchor="middle" fill="#d02090" fontSize="24" fontWeight="bold" fontFamily="serif">K.H.</text>
                    <path id="curve" d="M 40,160 Q 100,190 160,160" fill="transparent" />
                    <text width="200">
                      <textPath href="#curve" startOffset="50%" textAnchor="middle" fill="#00008B" fontSize="14" fontWeight="bold" letterSpacing="1">
                        THEN NANDIYALAM
                      </textPath>
                    </text>
                 </svg>
              </div>
            )}
          </div>

          {/* School Name */}
          <div className="space-y-3 w-full">
            <h1 className="text-2xl sm:text-3xl font-extrabold text-gray-900 tracking-tight leading-none">
              K. H. MATRICULATION
            </h1>
            <h2 className="text-lg sm:text-xl font-bold text-green-700 block leading-tight">
              BOYS HIGHER SECONDARY SCHOOL
            </h2>

            <div className="flex items-center justify-center gap-3 pt-2 opacity-80">
              <span className="h-px w-6 bg-blue-900/30"></span>
              <p className="text-sm font-bold text-blue-900 uppercase tracking-[0.2em] whitespace-nowrap">
                THEN NANDIYALAM
              </p>
              <span className="h-px w-6 bg-blue-900/30"></span>
            </div>
          </div>
        </div>

        {/* Login Card */}
        <div className="bg-white py-8 px-4 shadow-2xl shadow-gray-200/50 rounded-3xl sm:px-10 border border-gray-100 relative overflow-hidden">

          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-green-400 via-blue-500 to-purple-600"></div>

          {/* Role Switcher */}
          <div className="mb-8">
            <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-4 text-center">
              Login As
            </label>
            <div className="grid grid-cols-2 gap-4">
              <button
                type="button"
                onClick={() => handleRoleChange(UserRole.STUDENT)}
                className={`relative group p-4 rounded-2xl border-2 transition-all duration-300 ease-in-out ${
                  activeRole === UserRole.STUDENT 
                    ? 'border-green-500 bg-green-50 shadow-md shadow-green-100' 
                    : 'border-gray-100 bg-white hover:border-green-200 hover:bg-green-50/30'
                }`}
              >
                <div className="flex flex-col items-center gap-2">
                  <div className={`p-2 rounded-full ${activeRole === UserRole.STUDENT ? 'bg-green-100' : 'bg-gray-100 group-hover:bg-green-100'} transition-colors`}>
                    <GraduationCap className={`w-6 h-6 ${activeRole === UserRole.STUDENT ? 'text-green-700' : 'text-gray-400 group-hover:text-green-600'}`} />
                  </div>
                  <span className={`text-sm font-bold ${activeRole === UserRole.STUDENT ? 'text-green-900' : 'text-gray-500'}`}>Student</span>
                </div>
                {activeRole === UserRole.STUDENT && (
                  <div className="absolute top-3 right-3 text-green-600">
                    <CheckCircle2 className="w-4 h-4" />
                  </div>
                )}
              </button>

              <button
                type="button"
                onClick={() => handleRoleChange(UserRole.TEACHER)}
                className={`relative group p-4 rounded-2xl border-2 transition-all duration-300 ease-in-out ${
                  activeRole === UserRole.TEACHER 
                    ? 'border-blue-500 bg-blue-50 shadow-md shadow-blue-100' 
                    : 'border-gray-100 bg-white hover:border-blue-200 hover:bg-blue-50/30'
                }`}
              >
                <div className="flex flex-col items-center gap-2">
                  <div className={`p-2 rounded-full ${activeRole === UserRole.TEACHER ? 'bg-blue-100' : 'bg-gray-100 group-hover:bg-blue-100'} transition-colors`}>
                    <BookOpen className={`w-6 h-6 ${activeRole === UserRole.TEACHER ? 'text-blue-700' : 'text-gray-400 group-hover:text-blue-600'}`} />
                  </div>
                  <span className={`text-sm font-bold ${activeRole === UserRole.TEACHER ? 'text-blue-900' : 'text-gray-500'}`}>Teacher</span>
                </div>
                {activeRole === UserRole.TEACHER && (
                  <div className="absolute top-3 right-3 text-blue-600">
                    <CheckCircle2 className="w-4 h-4" />
                  </div>
                )}
              </button>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <Input
              label={activeRole === UserRole.STUDENT ? "Roll Number" : "Teacher ID"}
              placeholder={activeRole === UserRole.STUDENT ? "e.g. 10306" : "TCH001"}
              value={id}
              onChange={(e) => setId(e.target.value)}
              icon={<Lock className="w-5 h-5" />}
              required
              className="bg-gray-50 focus-within:bg-white transition-colors"
            />

            <Input
              label="Full Name"
              placeholder="As per records"
              value={name}
              onChange={(e) => setName(e.target.value)}
              icon={<User className="w-5 h-5" />}
              required
              className="bg-gray-50 focus-within:bg-white transition-colors"
            />

            {error && (
              <div className="p-4 rounded-xl bg-red-50 border border-red-100 text-red-600 text-sm flex items-center gap-3 animate-pulse">
                <span className="font-bold text-lg">!</span>
                <span>{error}</span>
              </div>
            )}

            <Button 
              type="submit" 
              fullWidth 
              isLoading={isLoading}
              variant={activeRole === UserRole.STUDENT ? 'primary' : 'secondary'}
              className={`h-14 text-lg font-bold shadow-xl hover:shadow-2xl transition-all transform hover:-translate-y-0.5 ${
                activeRole === UserRole.STUDENT 
                  ? '!bg-green-600 hover:!bg-green-700 shadow-green-500/30' 
                  : '!bg-blue-600 hover:!bg-blue-700 shadow-blue-500/30'
              }`}
            >
              {isLoading ? 'Verifying...' : 'Login Securely'}
            </Button>
          </form>
        </div>

        {/* Footer */}
        <div className="text-center space-y-3">
          <p className="text-xs text-gray-400 font-medium">
            &copy; {new Date().getFullYear()} K. H. Matriculation School
          </p>
          <div className="inline-flex items-center px-4 py-1.5 bg-white/80 backdrop-blur-sm rounded-full border border-gray-200 shadow-sm">
             <p className="text-[10px] text-gray-500 font-mono tracking-tight">
               <span className="font-bold text-green-600">TIP:</span> Use {activeRole === UserRole.STUDENT ? 'Class(10) + Sec(3) + Roll(06)' : 'ID (TCH001)'}
             </p>
          </div>
        </div>
      </div>
    </div>
  );
};

