import { MOCK_STUDENTS, MOCK_TEACHERS } from '../constants';
import { User, UserRole } from '../types';

export const login = async (identifier: string, name: string, role: UserRole): Promise<User> => {
  // Simulate network delay
  await new Promise(resolve => setTimeout(resolve, 800));

  let user: User | undefined;

  // 1. Try to find the user in the existing mock database (for consistent demo data)
  if (role === UserRole.STUDENT) {
    user = MOCK_STUDENTS.find(
      s => s.rollNumber.toLowerCase() === identifier.toLowerCase() && s.name.toLowerCase() === name.toLowerCase()
    );
  } else {
    user = MOCK_TEACHERS.find(
      t => t.id.toLowerCase() === identifier.toLowerCase() && t.name.toLowerCase() === name.toLowerCase()
    );
  }

  // 2. If not found in mock DB, create a temporary session user (Bypass Auth for testing)
  // This allows the user to enter any Name/ID and proceed to the dashboard as requested.
  if (!user) {
    if (role === UserRole.STUDENT) {
      user = {
        id: `TEMP-STU-${Date.now()}`,
        name: name || "Student",
        role: UserRole.STUDENT,
        classGrade: "11", // Default for new sessions
        section: "A",     // Default
        stream: "Science", // Default
        rollNumber: identifier || "0000",
        attendanceRate: 100, // Optimistic default
        avatarUrl: `https://ui-avatars.com/api/?name=${encodeURIComponent(name || 'Student')}&background=0D9488&color=fff`
      };
    } else {
      user = {
        id: identifier || `TEMP-TCH-${Date.now()}`,
        name: name || "Teacher",
        role: UserRole.TEACHER,
        subject: "General",
        assignedClasses: ["10-A", "11-B"],
        avatarUrl: `https://ui-avatars.com/api/?name=${encodeURIComponent(name || 'Teacher')}&background=4F46E5&color=fff`
      };
    }
  }

  return user;
};

