        <div className={`absolute -top-20 -right-20 w-64 h-64 ${bgClass} rounded-full opacity-40 blur-3xl pointer-events-none z-0`}></div>

        {/* Header */}
        <div className="flex justify-between items-center mb-2 relative z-50 shrink-0">
          <h2 className="text-xl font-bold text-gray-900 flex items-center gap-3">
            <div className={`p-2.5 rounded-2xl ${bgClass} bg-opacity-60`}>
                <Calendar className={`w-5 h-5 ${colorClass}`} />
            </div>
            Attendance
          </h2>
          <button 
            onClick={onClose} 
            className="p-2.5 bg-gray-50 border border-gray-100 rounded-full hover:bg-gray-100 active:scale-95 transition-all cursor-pointer shadow-sm text-gray-500 hover:text-gray-900"
            aria-label="Close"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Content */}
        <div className="flex flex-col items-center relative z-10 overflow-y-auto no-scrollbar pt-4">

            {/* Chart Section */}
            <div className="py-6 relative flex items-center justify-center">
                <div className="relative" style={{ width: size, height: size }}>
                    <svg width={size} height={size} className="transform -rotate-90 block">
                        {/* Track Circle */}
                        <circle
                            cx={center}
                            cy={center}
                            r={radius}
                            fill="transparent"
                            stroke="#f3f4f6" // gray-100
                            strokeWidth={strokeWidth}
                            strokeLinecap="round"
                        />
                        {/* Progress Circle */}
                        <circle
                            cx={center}
                            cy={center}
                            r={radius}
                            fill="transparent"
                            stroke={strokeColor}
                            strokeWidth={strokeWidth}
                            strokeDasharray={circumference}
                            strokeDashoffset={strokeDashoffset}
                            strokeLinecap="round"
                            className="transition-all duration-1000 ease-out"
                        />
                    </svg>

                    {/* Centered Text */}
                    <div className="absolute inset-0 flex flex-col items-center justify-center">
                        <span className={`text-5xl font-black ${colorClass} tracking-tight leading-none`}>
                            {percentage}%
                        </span>
                        <span className="text-xs font-bold text-gray-400 uppercase tracking-widest mt-2">
                            Overall
                        </span>
                    </div>
                </div>
            </div>

            {/* Status Card */}
            <div className={`w-full p-5 rounded-2xl ${bgClass} border border-opacity-60 ${isGood ? 'border-green-200' : 'border-red-200'} mb-5 mt-2`}>
                <div className="flex items-start gap-4">
                    <div className={`p-2 rounded-full bg-white bg-opacity-60 shrink-0`}>
                        {isGood ? (
