                </div>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 gap-4 w-full">
                <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100 flex flex-col items-center justify-center gap-1 hover:border-gray-200 transition-colors">
                    <span className="text-2xl font-black text-gray-900">142</span>
                    <span className="text-[11px] uppercase font-bold text-gray-400 tracking-wide">Working Days</span>
