const AttendanceModal: React.FC<{ percentage: number; onClose: () => void }> = ({ percentage, onClose }) => {
  const isGood = percentage >= 60;
  const colorClass = isGood ? 'text-green-500' : 'text-red-500';
  const bgClass = isGood ? 'bg-green-50' : 'bg-red-50';
  const strokeColor = isGood ? '#22c55e' : '#ef4444'; // green-500 : red-500

  // SVG Chart Configuration
  const size = 180;
  const strokeWidth = 14;
  const center = size / 2;
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (percentage / 100) * circumference;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200 px-4">
      <div 
        className="bg-white w-full max-w-sm rounded-[2rem] p-6 shadow-2xl transform transition-transform animate-in zoom-in-95 duration-300 relative overflow-hidden flex flex-col max-h-[90vh]"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Decorative Background Blob */}
        <div className={`absolute -top-20 -right-20 w-64 h-64 ${bgClass} rounded-full opacity-40 blur-3xl pointer-events-none z-0`}></div>

        {/* Header */}
        <div className="flex justify-between items-center mb-2 relative z-50 shrink-0">
          <h2 className="text-xl font-bold text-gray-900 flex items-center gap-3">
            <div className={`p-2.5 rounded-2xl ${bgClass} bg-opacity-60`}>
                <Calendar className={`w-5 h-5 ${colorClass}`} />
            </div>
            Attendance
          </h2>
          <button 
            onClick={onClose} 
            className="p-2.5 bg-gray-50 border border-gray-100 rounded-full hover:bg-gray-100 active:scale-95 transition-all cursor-pointer shadow-sm text-gray-500 hover:text-gray-900"
            aria-label="Close"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Content */}
        <div className="flex flex-col items-center relative z-10 overflow-y-auto no-scrollbar pt-4">

            {/* Chart Section */}
            <div className="py-6 relative flex items-center justify-center">
                <div className="relative" style={{ width: size, height: size }}>
                    <svg width={size} height={size} className="transform -rotate-90 block">
                        {/* Track Circle */}
                        <circle
                            cx={center}
                            cy={center}
                            r={radius}
                            fill="transparent"
                            stroke="#f3f4f6" // gray-100
                            strokeWidth={strokeWidth}
                            strokeLinecap="round"
                        />
                        {/* Progress Circle */}
                        <circle
                            cx={center}
                            cy={center}
                            r={radius}
                            fill="transparent"
                            stroke={strokeColor}
                            strokeWidth={strokeWidth}
                            strokeDasharray={circumference}
                            strokeDashoffset={strokeDashoffset}
                            strokeLinecap="round"
                            className="transition-all duration-1000 ease-out"
                        />
                    </svg>

                    {/* Centered Text */}
                    <div className="absolute inset-0 flex flex-col items-center justify-center">
                        <span className={`text-5xl font-black ${colorClass} tracking-tight leading-none`}>
                            {percentage}%
                        </span>
                        <span className="text-xs font-bold text-gray-400 uppercase tracking-widest mt-2">
                            Overall
                        </span>
                    </div>
                </div>
            </div>

            {/* Status Card */}
            <div className={`w-full p-5 rounded-2xl ${bgClass} border border-opacity-60 ${isGood ? 'border-green-200' : 'border-red-200'} mb-5 mt-2`}>
                <div className="flex items-start gap-4">
                    <div className={`p-2 rounded-full bg-white bg-opacity-60 shrink-0`}>
                        {isGood ? (
                            <TrendingUp className={`w-5 h-5 ${colorClass}`} />
                        ) : (
                            <AlertCircle className={`w-5 h-5 ${colorClass}`} />
                        )}
                    </div>
                    <div>
                        <h3 className={`font-bold text-base ${colorClass} mb-1`}>
                            {isGood ? 'On Track' : 'Attention Needed'}
                        </h3>
                        <p className="text-sm text-gray-600 leading-relaxed opacity-90">
                            {isGood 
                            ? "Your attendance record is excellent. Keep up the consistency!" 
                            : "You are falling below the 75% requirement. Please meet your coordinator."}
                        </p>
                    </div>
                </div>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 gap-4 w-full">
                <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100 flex flex-col items-center justify-center gap-1 hover:border-gray-200 transition-colors">
                    <span className="text-2xl font-black text-gray-900">142</span>
                    <span className="text-[11px] uppercase font-bold text-gray-400 tracking-wide">Working Days</span>
                </div>
                <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100 flex flex-col items-center justify-center gap-1 hover:border-gray-200 transition-colors">
                    <span className={`text-2xl font-black ${colorClass}`}>
                        {Math.round(142 * (percentage/100))}
                    </span>
                    <span className="text-[11px] uppercase font-bold text-gray-400 tracking-wide">Days Present</span>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

