                  <div className={`p-1.5 rounded-lg ${period.color}`}>
                    {period.icon}
                  </div>
                </div>
                <h3 className={`text-base font-bold ${period.isBreak ? 'text-amber-900 opacity-70' : 'text-gray-900'}`}>
                  {period.subject}
                </h3>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

