      {/* Header */}
      <div className="bg-white/80 backdrop-blur-md sticky top-0 z-20 pt-12 pb-2 border-b border-gray-100 shadow-sm">
        <div className="flex justify-between items-center px-5 mb-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 rounded-xl bg-blue-50 text-blue-600">
                <Clock className="w-6 h-6" />
            </div>
            <div>
                <h2 className="text-xl font-black text-gray-900 tracking-tight leading-none">
                    Time Table
                </h2>
                <p className="text-xs font-medium text-gray-500 mt-0.5">Class {className} Schedule</p>
            </div>
          </div>
          <button 
            onClick={onClose} 
            className="p-2.5 bg-gray-100 border border-gray-200 rounded-full hover:bg-gray-200 active:scale-95 transition-all cursor-pointer shadow-sm text-gray-600"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex overflow-x-auto no-scrollbar gap-2 px-5 pb-2">
          {days.map((day) => (
            <button
              key={day}
              onClick={() => setSelectedDay(day)}
              className={`flex-shrink-0 px-4 py-2 rounded-full text-xs font-bold transition-all duration-300 ${
                selectedDay === day 
                  ? 'bg-blue-600 text-white shadow-md shadow-blue-200 scale-105' 
                  : 'bg-white text-gray-500 border border-gray-100 hover:bg-gray-50'
              }`}
            >
              {day.slice(0, 3)}
            </button>
          ))}
        </div>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar p-5">
        <div className="relative border-l-2 border-gray-100 ml-3 space-y-6 pb-20">
          {periods.map((period, index) => (
            <div key={index} className="relative pl-6 animate-in fade-in slide-in-from-bottom-2 duration-500" style={{ animationDelay: `${index * 50}ms` }}>
              <div className={`absolute -left-[9px] top-3 w-4 h-4 rounded-full border-2 border-white shadow-sm z-10 ${period.isBreak ? 'bg-amber-400' : 'bg-blue-500'}`}></div>
              <div className={`p-4 rounded-2xl border ${period.isBreak ? 'bg-amber-50/50 border-amber-100' : 'bg-white border-gray-100'} shadow-sm transition-transform hover:scale-[1.02] active:scale-98`}>
                <div className="flex justify-between items-center mb-2">
                  <span className="text-xs font-bold text-gray-400 font-mono bg-white/50 px-2 py-0.5 rounded-md">{period.time}</span>
                  <div className={`p-1.5 rounded-lg ${period.color}`}>
                    {period.icon}
                  </div>
                </div>
                <h3 className={`text-base font-bold ${period.isBreak ? 'text-amber-900 opacity-70' : 'text-gray-900'}`}>
                  {period.subject}
                </h3>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

