                  <p className="text-[11px] text-gray-500">Annual Sports Day • Next Friday</p>
                </div>
                <ChevronRight className="w-4 h-4 text-gray-300" />
             </button>

             {/* Circulars - Full Width */}
             <button 
               onClick={() => setShowCirculars(true)}
               className="w-full bg-white p-3.5 rounded-2xl shadow-sm border border-gray-100 flex items-center gap-3 transition-transform hover:scale-[1.02] active:scale-98"
             >
                <div className="w-10 h-10 rounded-xl bg-indigo-50 text-indigo-600 flex items-center justify-center shrink-0">
                  <FileText className="w-5 h-5" />
                </div>
                <div className="flex-1 text-left">
                  <h3 className="text-sm font-bold text-gray-900">Circulars</h3>
                  <p className="text-[11px] text-gray-500">Official Notices & Updates</p>
                </div>
                <ChevronRight className="w-4 h-4 text-gray-300" />
             </button>
          </div>
        </section>

        {/* School Info Footer */}
        <div className="flex items-center justify-center gap-2 mt-6 opacity-40 grayscale pb-6">
          <div className="w-5 h-5 overflow-hidden">
             {!imgError ? (
               <img 
                 src="kh-logo.png" 
                 alt="Logo" 
                 className="w-full h-full object-contain"
                 onError={() => setImgError(true)} 
               />
             ) : (
               <School className="w-4 h-4" />
             )}
          </div>
          <span className="text-[10px] font-bold text-gray-600">K.H. Matriculation</span>
        </div>
      </main>

      {/* Floating Bottom Navigation - Single Item Pill */}
      <div className="fixed bottom-8 left-0 right-0 z-50 flex justify-center">
        <div className="bg-white/80 backdrop-blur-xl p-1.5 rounded-full shadow-[0_8px_30px_rgb(0,0,0,0.12)] border border-white/20 ring-1 ring-gray-100">
          <button
            onClick={() => setShowCamConnect(true)}
            className="flex items-center gap-2.5 px-6 py-3 rounded-full bg-gray-900 text-white shadow-lg shadow-gray-900/20 hover:bg-gray-800 hover:scale-[1.02] active:scale-95 transition-all duration-300"
          >
             <Users className="w-4 h-4 text-indigo-300" />
             <span className="font-bold text-sm tracking-wide">Community</span>
          </button>
        </div>
      </div>

      {/* Modals */}
      {isProfileOpen && <ProfileModal user={user} onClose={() => setIsProfileOpen(false)} onLogout={onLogout} />}
      {showAttendance && <AttendanceModal percentage={attendancePercentage} onClose={() => setShowAttendance(false)} />}
      {showHomework && <HomeworkModal onClose={() => setShowHomework(false)} />}
      {showTimetable && <TimetableModal user={user} onClose={() => setShowTimetable(false)} />}
      {showResults && <ResultsModal onClose={() => setShowResults(false)} />}
      {showAssignments && <AssignmentsModal onClose={() => setShowAssignments(false)} />}
      {showFees && <FeesModal onClose={() => setShowFees(false)} />}
      {showCamConnect && <CamConnectModal onClose={() => setShowCamConnect(false)} />}
      {showEvents && <EventsModal onClose={() => setShowEvents(false)} />}
      {showCirculars && <CircularsModal onClose={() => setShowCirculars(false)} />}
    </div>
  );
};
